#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int D[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &D[i]);
        }
        for (int i = 0; i < Q; i++) {
            int X;
            scanf("%d", &X);
            for (int j = 0; j < N; j++) {
                X = floor((double)X / D[j]);
            }
            printf("%d ", X);
        }
        printf("\n");
    }
    return 0;
}

