code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int Q = scanner.nextInt();
            int[] D = new int[N];
            for (int i = 0; i < N; i++) {
                D[i] = scanner.nextInt();
            }
            for (int i = 0; i < Q; i++) {
                int X = scanner.nextInt();
                for (int j = 0; j < N; j++) {
                    X = (int) Math.floor((double) X / D[j]);
                }
                System.out.print(X + " ");
            }
            System.out.println();
        }
    }
}

