code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, Q] = readline().split(' ').map(Number);
    const D = readline().split(' ').map(Number);
    const queries = readline().split(' ').map(Number);
    for (let query of queries) {
        for (let d of D) {
            query = Math.floor(query / d);
        }
        process.stdout.write(query + ' ');
    }
    process.stdout.write('\n');
}
